import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"11B. No Amalgamation Of Wards Without Agreement Of Anmf And","description":"","frontmatter":{"title":"11B. No Amalgamation Of Wards Without Agreement Of Anmf And","eba":"Nurses and Midwives 2024-2028","topics":["consultation","disputes","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/11B-no-amalgamation-of-wards-without-agreement-of-anmf-and.md","filePath":"ebas/nurses-midwives/consultation-disputes/11B-no-amalgamation-of-wards-without-agreement-of-anmf-and.md"}'),s={name:"ebas/nurses-midwives/consultation-disputes/11B-no-amalgamation-of-wards-without-agreement-of-anmf-and.md"};function i(r,e,d,m,l,u){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_11b-no-amalgamation-of-wards-without-agreement-of-anmf-and" tabindex="-1">11B. No Amalgamation Of Wards Without Agreement Of Anmf And <a class="header-anchor" href="#_11b-no-amalgamation-of-wards-without-agreement-of-anmf-and" aria-label="Permalink to &quot;11B. No Amalgamation Of Wards Without Agreement Of Anmf And&quot;">​</a></h1><p>Employer</p><p><strong>11B.1</strong> A proposed amalgamation of wards will be subject to consultation under <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a>, save that <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11.10</a> will not apply and instead the dispute will be notified to the Statewide Industry Panel under <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14</a>.</p><p><strong>11B.2</strong> During the life of the Agreement there will be no amalgamation of wards that will result in:</p><p><strong>(a)</strong> an increase in workload for the Employees working in those wards who are covered by this Agreement; or</p><p><strong>(b)</strong> increase in patient risk (in those wards),</p><p>without the agreement of the ANMF and the Employer.</p><p><strong>11B.3</strong> The Statewide Industry Panel will have regard to the DOH&#39;s Guidelines which will reflect historical and contemporary practice and standards.</p>',8)])])}const p=a(s,[["render",i]]);export{h as __pageData,p as default};
